    "name": "WorksExtract",
    "label": "Works Extract",
    "description": "Extract works (laws, reports, books, products, artworks) from text using LLM.",
    "category": "work",
    "icon": "BookOpen",
    "color": "bg-teal-500",
    "requiredUpstreamNodes": [],
    "dependencyHelperText": "Requires text input or JSON with a \"text\" attribute.",
